import { IMentor } from '@/models/mentor.model';
import { UpdateMentorProfileDto } from '@/dto/mentorRequest.dto';

export interface IMentorService {
    getMentorProfile(id: string): Promise<IMentor>;
    updateMentorProfileBasicInfo(
        id: string,
        data: UpdateMentorProfileDto
    ): Promise<IMentor>;
    updateMentorProfileMedia(
        id: string,
        files: {
            [fieldName: string]: (Express.Multer.File & { location: string })[];
        }
    ): Promise<IMentor>;
    updateMentorProfileArray(
        id: string,
        field: string,
        data: string[]
    ): Promise<IMentor>;
    getApprovedMentors(
        page: number,
        limit: number,
        search: string,
        sort: string,
        filter: {
            expertise?: { $regex: string; $options: string };
            monthlyCharge?: { $gte?: number; $lte?: number };
            rating?: { $gte: number };
        }
    ): Promise<{ mentors: IMentor[]; total: number; pages: number }>;
    getMentorById(id: string): Promise<IMentor | null>;
}
